cases.sql:
SELECT COUNT(*) AS movie_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS days_above_30
FROM seattle_weather
WHERE temp_max > 30;

SELECT
  100.0 * SUM(CASE WHEN order_status = 'canceled' THEN 1 ELSE 0 END) / COUNT(*) AS pct_canceled
FROM olist_orders;

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE date_part('year', order_purchase_timestamp) = 2099;

SELECT COUNT(*) AS snow_days_over_40
FROM seattle_weather
WHERE weather = 'snow' AND temp_max > 40;
